1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { runScenario } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // === Quote: empty and basic single items ===
7	  it("should return premium of 5 G (processing fee only) for an empty item list", () => {
8	    const result = runScenario({
9	      command: "quote",
10	      customer: { yearsInsured: 0, contractNumber: 1 },
11	      items: [],
12	    });
13	    expect(result).toEqual({ premium: 5 });
14	  });
15	  it.todo("should quote a single sword at 110 G (100 base + 10 first-insurance + 5 fee)");
16	  it.todo("should quote a single amulet at 71 G (60 base + 6 first-insurance + 5 fee)");
17	  it.todo("should quote a single staff at 93 G (80 base + 8 first-insurance + 5 fee)");
18	  it.todo("should quote a single potion at 49 G (40 base + 4 first-insurance + 5 fee)");
19	  it.todo("should quote a single rune at 33 G (25 base + 2.5 first-insurance + 5 fee, rounded up)");
20	  it.todo("should quote a single moonstone at 33 G (25 base + 2.5 first-insurance + 5 fee, rounded up)");
21	
22	  // === Quote: multiple distinct items ===
23	  it.todo("should quote multiple distinct items by summing their item premiums plus the 5 G fee");
24	
25	  // === Quote: components and blocks of 3 alike ===
26	  it.todo("should quote exactly 3 alike runes as a block with 60 G base premium (plus first-insurance and fee)");
27	  it.todo("should quote exactly 3 alike moonstones as a block with 60 G base premium (plus first-insurance and fee)");
28	  it.todo("should NOT treat 4 alike runes as a block (charge each rune individually)");
29	  it.todo("should NOT treat 2 alike runes as a block (charge each rune individually)");
30	
31	  // === Quote: item-specific modifiers ===
32	  it.todo("should add 50% cursed surcharge on a cursed item's base premium");
33	  it.todo("should add 30% high-enchantment surcharge for an item with enchantment >= 5");
34	  it.todo("should NOT add high-enchantment surcharge for enchantment level < 5");
35	  it.todo("should stack cursed and high-enchantment surcharges additively on the item's base premium");
36	
37	  // === Quote: policy-wide modifiers ===
38	  it.todo("should apply -20% loyalty discount when customer has been insured for >= 2 years");
39	  it.todo("should NOT apply loyalty discount when customer has been insured < 2 years");
40	  it.todo("should apply -15% follow-up discount for the customer's second contract");
41	  it.todo("should NOT apply follow-up discount for the customer's first contract");
42	
43	  // === Quote: multiple items of same type (separate insurance) ===
44	  it.todo("should treat two swords as separate insurance entries (each charged individually)");
45	
46	  // === Quote: rounding ===
47	  it.todo("should round the final premium UP to whole G in MHPCO's favor");
48	
49	  // === Quote: integration examples from spec ===
50	  it.todo("should quote newcomer's cursed sword (steel, enchantment 3) at 165 G");
51	  it.todo("should quote 3-year customer's 2nd contract cursed sword (steel, enchantment 7) at 160 G");
52	
53	  // === Claim: basic single damage ===
54	  it.todo("should pay out damage minus 100 G deductible for a single damaged item");
55	  it.todo("should report remainingCap as 2x unmodified insurance sum minus payout after a claim");
56	
57	  // === Claim: enchantment and material clauses ===
58	  it.todo("should pay only 50% reimbursement when damaged item has enchantment >= 8");
59	  it.todo("should pay full reimbursement when damaged item is made of dragon material (overrides 50% clause)");
60	  it.todo("should NOT apply enchantment/material clauses to runes or moonstones");
61	
62	  // === Claim: cap enforcement ===
63	  it.todo("should cap total payout at 2x unmodified insurance sum across multiple claim events");
64	  it.todo("should round payout DOWN to whole G in MHPCO's favor");
65	
66	  // === CLI integration / error cases ===
67	  it.todo("should exit non-zero and write to stderr when quote contains an unknown item type");
68	  it.todo("should exit non-zero when a claim references an item not in the policy");
69	  it.todo("should exit non-zero when a claim has more damage entries of a type than the policy covers");
70	  it.todo("should exit non-zero when a claim contains a negative damage amount");
71	});
72

